export function useAutoSuggestions(context: QuestionContext | null, enabled = true) {
  const { fetchSuggestions, clearSuggestions } = useAISuggestions();

  useEffect(() => {
    if (enabled && context) {
      fetchSuggestions(context);
    } else {
      clearSuggestions();
    }

    return () => {
      clearSuggestions();
    };
  }, [context?.questionId, enabled]);
}

