/**
 * TOTP Verification Component
 * Displays code input for MFA verification
 */

import { useState, useCallback, useRef, useEffect } from 'react';
import { ShieldCheck, AlertCircle } from 'lucide-react';
import { Button, Card } from '../ui';
import clsx from 'clsx';

export interface TOTPVerificationProps {
  /** Called when code is submitted */
  onVerify: (code: string) => Promise<void>;
  /** Title to display */
  title?: string;
  /** Description text */
  description?: string;
  /** Show backup code option */
  showBackupCodeOption?: boolean;
  /** Called when backup code option is selected */
  onUseBackupCode?: () => void;
  /** Loading state */
  isLoading?: boolean;
  /** Error message */
  error?: string | null;
  /** Custom class name */
  className?: string;
}

export function TOTPVerification({
  onVerify,
  title = 'Two-Factor Authentication',
  description = 'Enter the 6-digit code from your authenticator app',
  showBackupCodeOption = true,
  onUseBackupCode,
  isLoading = false,
  error,
  className,
}: TOTPVerificationProps) {
  const [code, setCode] = useState<string[]>(Array(6).fill(''));
  const [isSubmitting, setIsSubmitting] = useState(false);
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  // Focus first input on mount
  useEffect(() => {
    inputRefs.current[0]?.focus();
  }, []);

  // Handle digit input
  const handleChange = useCallback(
    (index: number, value: string) => {
      // Only allow digits
      const digit = value.replace(/\D/g, '').slice(-1);

      const newCode = [...code];
      newCode[index] = digit;
      setCode(newCode);

      // Auto-advance to next input
      if (digit && index < 5) {
        inputRefs.current[index + 1]?.focus();
      }

      // Auto-submit when all digits entered
      if (digit && index === 5 && newCode.every((d) => d)) {
        handleSubmit(newCode.join(''));
      }
    },
    [code],
  );

  // Handle key events
  const handleKeyDown = useCallback(
    (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Backspace' && !code[index] && index > 0) {
        inputRefs.current[index - 1]?.focus();
      } else if (e.key === 'ArrowLeft' && index > 0) {
        inputRefs.current[index - 1]?.focus();
      } else if (e.key === 'ArrowRight' && index < 5) {
        inputRefs.current[index + 1]?.focus();
      }
    },
    [code],
  );

  // Handle paste
  const handlePaste = useCallback(
    (e: React.ClipboardEvent) => {
      e.preventDefault();
      const pasted = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, 6);
      const newCode = [...code];
      for (let i = 0; i < pasted.length; i++) {
        newCode[i] = pasted[i];
      }
      setCode(newCode);

      // Focus appropriate input
      if (pasted.length < 6) {
        inputRefs.current[pasted.length]?.focus();
      } else {
        inputRefs.current[5]?.focus();
        handleSubmit(pasted);
      }
    },
    [code],
  );

  // Submit handler
  const handleSubmit = useCallback(
    async (codeStr: string) => {
      if (codeStr.length !== 6 || isSubmitting || isLoading) return;

      setIsSubmitting(true);
      try {
        await onVerify(codeStr);
      } finally {
        setIsSubmitting(false);
      }
    },
    [onVerify, isSubmitting, isLoading],
  );

  // Manual submit button
  const handleButtonSubmit = useCallback(() => {
    const codeStr = code.join('');
    if (codeStr.length === 6) {
      handleSubmit(codeStr);
    }
  }, [code, handleSubmit]);

  const loading = isSubmitting || isLoading;

  return (
    <Card className={clsx('max-w-md mx-auto', className)}>
      <div className="text-center mb-6">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-brand-100 rounded-full mb-4">
          <ShieldCheck className="h-8 w-8 text-brand-600" />
        </div>
        <h2 className="text-xl font-semibold text-surface-900">{title}</h2>
        <p className="text-surface-500 mt-2 text-sm">{description}</p>
      </div>

      {/* Code Input */}
      <div className="flex justify-center gap-2 mb-6">
        {code.map((digit, index) => (
          <input
            key={index}
            ref={(el) => {
              inputRefs.current[index] = el;
            }}
            type="text"
            inputMode="numeric"
            maxLength={1}
            value={digit}
            onChange={(e) => handleChange(index, e.target.value)}
            onKeyDown={(e) => handleKeyDown(index, e)}
            onPaste={handlePaste}
            disabled={loading}
            className={clsx(
              'w-12 h-14 text-center text-2xl font-bold border-2 rounded-lg',
              'focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-brand-500',
              'transition-colors',
              error ? 'border-danger-300 bg-danger-50' : 'border-surface-300 bg-white',
              loading && 'opacity-50 cursor-not-allowed',
            )}
            autoComplete="one-time-code"
          />
        ))}
      </div>

      {/* Error Message */}
      {error && (
        <div className="flex items-center justify-center gap-2 text-danger-600 text-sm mb-4">
          <AlertCircle className="h-4 w-4" />
          <span>{error}</span>
        </div>
      )}

      {/* Submit Button */}
      <Button
        variant="primary"
        className="w-full"
        onClick={handleButtonSubmit}
        disabled={code.join('').length !== 6 || loading}
        loading={loading}
      >
        {loading ? 'Verifying...' : 'Verify Code'}
      </Button>

      {/* Backup Code Option */}
      {showBackupCodeOption && onUseBackupCode && (
        <div className="mt-4 text-center">
          <button
            type="button"
            onClick={onUseBackupCode}
            className="text-sm text-brand-600 hover:text-brand-700 transition-colors"
            disabled={loading}
          >
            Use a backup code instead
          </button>
        </div>
      )}
    </Card>
  );
}

export default TOTPVerification;

/**
 * Comments.tsx - Comment & Discussion System
 * Sprint 35 Task 5: Comment threads on questions with @mentions
 *
 * Nielsen Heuristics Addressed:
 * - #1 Visibility: Show comment counts, unread indicators
 * - #4 Consistency: Standard comment UI patterns
 * - #7 Flexibility: @mentions, reactions, threading
 * - #10 Help: Contextual discussions for clarification
 */

import React, {
  createContext,
  useContext,
  useState,
  useCallback,
  useEffect,
  useRef,
  useMemo,
} from 'react';

// ============================================================================
// Types & Interfaces
// ============================================================================

export interface User {
  id: string;
  name: string;
  email: string;
  avatar?: string;
  role?: string;
}

export interface Mention {
  userId: string;
  userName: string;
  startIndex: number;
  endIndex: number;
}

export interface Reaction {
  emoji: string;
  userId: string;
  userName: string;
  createdAt: Date;
}

export interface Comment {
  id: string;
  questionId: string;
  parentId?: string; // For threaded replies
  content: string;
  mentions: Mention[];
  reactions: Reaction[];
  author: User;
  createdAt: Date;
  updatedAt?: Date;
  isEdited: boolean;
  isResolved: boolean;
  isPinned: boolean;
}

export interface CommentThread {
  id: string;
  questionId: string;
  rootComment: Comment;
  replies: Comment[];
  isExpanded: boolean;
  unreadCount: number;
}

export interface CommentNotification {
  id: string;
  type: 'mention' | 'reply' | 'reaction' | 'resolved';
  commentId: string;
  questionId: string;
  fromUser: User;
  message: string;
  createdAt: Date;
  isRead: boolean;
}

export interface CommentDraft {
  questionId: string;
  parentId?: string;
  content: string;
  mentions: Mention[];
  savedAt: Date;
}

export interface CommentsContextValue {
  threads: Map<string, CommentThread[]>;
  notifications: CommentNotification[];
  unreadCount: number;
  drafts: Map<string, CommentDraft>;
  currentUser: User | null;
  teamMembers: User[];

  // Actions
  setCurrentUser: (user: User) => void;
  setTeamMembers: (members: User[]) => void;
  addComment: (
    questionId: string,
    content: string,
    mentions: Mention[],
    parentId?: string,
  ) => Comment;
  editComment: (commentId: string, content: string, mentions: Mention[]) => void;
  deleteComment: (commentId: string) => void;
  resolveThread: (threadId: string) => void;
  pinComment: (commentId: string) => void;
  addReaction: (commentId: string, emoji: string) => void;
  removeReaction: (commentId: string, emoji: string) => void;
  markNotificationRead: (notificationId: string) => void;
  markAllNotificationsRead: () => void;
  saveDraft: (questionId: string, content: string, mentions: Mention[], parentId?: string) => void;
  getDraft: (questionId: string, parentId?: string) => CommentDraft | undefined;
  clearDraft: (questionId: string, parentId?: string) => void;
  getThreadsForQuestion: (questionId: string) => CommentThread[];
  getCommentCount: (questionId: string) => number;
}

// ============================================================================
// Context
// ============================================================================

const CommentsContext = createContext<CommentsContextValue | null>(null);

export const useComments = (): CommentsContextValue => {
  const context = useContext(CommentsContext);
  if (!context) {
    throw new Error('useComments must be used within a CommentsProvider');
  }
  return context;
};

// ============================================================================
// Storage Keys
// ============================================================================

const STORAGE_KEYS = {
  THREADS: 'quiz2biz_comment_threads',
  NOTIFICATIONS: 'quiz2biz_comment_notifications',
  DRAFTS: 'quiz2biz_comment_drafts',
};

// ============================================================================
// Provider Component
// ============================================================================

interface CommentsProviderProps {
  children: React.ReactNode;
  initialUser?: User;
  initialTeamMembers?: User[];
}

export const CommentsProvider: React.FC<CommentsProviderProps> = ({
  children,
  initialUser,
  initialTeamMembers = [],
}) => {
  const [threads, setThreads] = useState<Map<string, CommentThread[]>>(new Map());
  const [notifications, setNotifications] = useState<CommentNotification[]>([]);
  const [drafts, setDrafts] = useState<Map<string, CommentDraft>>(new Map());
  const [currentUser, setCurrentUser] = useState<User | null>(initialUser || null);
  const [teamMembers, setTeamMembers] = useState<User[]>(initialTeamMembers);

  // Load from localStorage on mount
  useEffect(() => {
    try {
      const savedThreads = localStorage.getItem(STORAGE_KEYS.THREADS);
      if (savedThreads) {
        const parsed = JSON.parse(savedThreads);
        const threadsMap = new Map<string, CommentThread[]>();
        Object.entries(parsed).forEach(([key, value]) => {
          threadsMap.set(key, value as CommentThread[]);
        });
        setThreads(threadsMap);
      }

      const savedNotifications = localStorage.getItem(STORAGE_KEYS.NOTIFICATIONS);
      if (savedNotifications) {
        setNotifications(JSON.parse(savedNotifications));
      }

      const savedDrafts = localStorage.getItem(STORAGE_KEYS.DRAFTS);
      if (savedDrafts) {
        const parsed = JSON.parse(savedDrafts);
        const draftsMap = new Map<string, CommentDraft>();
        Object.entries(parsed).forEach(([key, value]) => {
          draftsMap.set(key, value as CommentDraft);
        });
        setDrafts(draftsMap);
      }
    } catch (error) {
      console.error('Failed to load comments from storage:', error);
    }
  }, []);

  // Save threads to localStorage
  useEffect(() => {
    const obj: Record<string, CommentThread[]> = {};
    threads.forEach((value, key) => {
      obj[key] = value;
    });
    localStorage.setItem(STORAGE_KEYS.THREADS, JSON.stringify(obj));
  }, [threads]);

  // Save notifications to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.NOTIFICATIONS, JSON.stringify(notifications));
  }, [notifications]);

  // Save drafts to localStorage
  useEffect(() => {
    const obj: Record<string, CommentDraft> = {};
    drafts.forEach((value, key) => {
      obj[key] = value;
    });
    localStorage.setItem(STORAGE_KEYS.DRAFTS, JSON.stringify(obj));
  }, [drafts]);

  const unreadCount = useMemo(() => {
    return notifications.filter((n) => !n.isRead).length;
  }, [notifications]);

  const generateId = (): string => {
    return `comment_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  };

  const createNotification = useCallback(
    (
      type: CommentNotification['type'],
      commentId: string,
      questionId: string,
      fromUser: User,
      message: string,
    ) => {
      const notification: CommentNotification = {
        id: generateId(),
        type,
        commentId,
        questionId,
        fromUser,
        message,
        createdAt: new Date(),
        isRead: false,
      };
      setNotifications((prev) => [notification, ...prev]);
    },
    [],
  );

  // Define helper function and clearDraft before addComment since addComment uses them
  const getDraftKey = (questionId: string, parentId?: string): string => {
    return parentId ? `${questionId}_${parentId}` : questionId;
  };

  const clearDraft = useCallback((questionId: string, parentId?: string) => {
    const key = getDraftKey(questionId, parentId);
    setDrafts((prev) => {
      const newDrafts = new Map(prev);
      newDrafts.delete(key);
      return newDrafts;
    });
  }, []);

  const addComment = useCallback(
    (questionId: string, content: string, mentions: Mention[], parentId?: string): Comment => {
      if (!currentUser) {
        throw new Error('Must be logged in to add comments');
      }

      const comment: Comment = {
        id: generateId(),
        questionId,
        parentId,
        content,
        mentions,
        reactions: [],
        author: currentUser,
        createdAt: new Date(),
        isEdited: false,
        isResolved: false,
        isPinned: false,
      };

      setThreads((prev) => {
        const newThreads = new Map(prev);
        const questionThreads = newThreads.get(questionId) || [];

        if (parentId) {
          // Add as reply to existing thread
          const updatedThreads = questionThreads.map((thread) => {
            if (
              thread.rootComment.id === parentId ||
              thread.replies.some((r) => r.id === parentId)
            ) {
              return {
                ...thread,
                replies: [...thread.replies, comment],
              };
            }
            return thread;
          });
          newThreads.set(questionId, updatedThreads);
        } else {
          // Create new thread
          const newThread: CommentThread = {
            id: generateId(),
            questionId,
            rootComment: comment,
            replies: [],
            isExpanded: true,
            unreadCount: 0,
          };
          newThreads.set(questionId, [...questionThreads, newThread]);
        }

        return newThreads;
      });

      // Create notifications for mentions
      mentions.forEach((mention) => {
        const mentionedUser = teamMembers.find((m) => m.id === mention.userId);
        if (mentionedUser && mentionedUser.id !== currentUser.id) {
          createNotification(
            'mention',
            comment.id,
            questionId,
            currentUser,
            `${currentUser.name} mentioned you in a comment`,
          );
        }
      });

      // Clear draft after successful post
      clearDraft(questionId, parentId);

      return comment;
    },
    [currentUser, teamMembers, createNotification],
  );

  const editComment = useCallback((commentId: string, content: string, mentions: Mention[]) => {
    setThreads((prev) => {
      const newThreads = new Map(prev);

      newThreads.forEach((questionThreads, questionId) => {
        const updatedThreads = questionThreads.map((thread) => {
          if (thread.rootComment.id === commentId) {
            return {
              ...thread,
              rootComment: {
                ...thread.rootComment,
                content,
                mentions,
                updatedAt: new Date(),
                isEdited: true,
              },
            };
          }

          const updatedReplies = thread.replies.map((reply) => {
            if (reply.id === commentId) {
              return {
                ...reply,
                content,
                mentions,
                updatedAt: new Date(),
                isEdited: true,
              };
            }
            return reply;
          });

          return { ...thread, replies: updatedReplies };
        });

        newThreads.set(questionId, updatedThreads);
      });

      return newThreads;
    });
  }, []);

  const deleteComment = useCallback((commentId: string) => {
    setThreads((prev) => {
      const newThreads = new Map(prev);

      newThreads.forEach((questionThreads, questionId) => {
        // Filter out threads where root comment matches
        let updatedThreads = questionThreads.filter(
          (thread) => thread.rootComment.id !== commentId,
        );

        // Remove from replies
        updatedThreads = updatedThreads.map((thread) => ({
          ...thread,
          replies: thread.replies.filter((reply) => reply.id !== commentId),
        }));

        newThreads.set(questionId, updatedThreads);
      });

      return newThreads;
    });
  }, []);

  const resolveThread = useCallback((threadId: string) => {
    setThreads((prev) => {
      const newThreads = new Map(prev);

      newThreads.forEach((questionThreads, questionId) => {
        const updatedThreads = questionThreads.map((thread) => {
          if (thread.id === threadId) {
            return {
              ...thread,
              rootComment: {
                ...thread.rootComment,
                isResolved: !thread.rootComment.isResolved,
              },
            };
          }
          return thread;
        });

        newThreads.set(questionId, updatedThreads);
      });

      return newThreads;
    });
  }, []);

  const pinComment = useCallback((commentId: string) => {
    setThreads((prev) => {
      const newThreads = new Map(prev);

      newThreads.forEach((questionThreads, questionId) => {
        const updatedThreads = questionThreads.map((thread) => {
          if (thread.rootComment.id === commentId) {
            return {
              ...thread,
              rootComment: {
                ...thread.rootComment,
                isPinned: !thread.rootComment.isPinned,
              },
            };
          }
          return thread;
        });

        newThreads.set(questionId, updatedThreads);
      });

      return newThreads;
    });
  }, []);

  const addReaction = useCallback(
    (commentId: string, emoji: string) => {
      if (!currentUser) {
        return;
      }

      setThreads((prev) => {
        const newThreads = new Map(prev);

        newThreads.forEach((questionThreads, questionId) => {
          const updatedThreads = questionThreads.map((thread) => {
            const updateReactions = (comment: Comment): Comment => {
              if (comment.id !== commentId) {
                return comment;
              }

              // Check if user already reacted with this emoji
              const existingReaction = comment.reactions.find(
                (r) => r.emoji === emoji && r.userId === currentUser.id,
              );

              if (existingReaction) {
                return comment; // Already reacted
              }

              return {
                ...comment,
                reactions: [
                  ...comment.reactions,
                  {
                    emoji,
                    userId: currentUser.id,
                    userName: currentUser.name,
                    createdAt: new Date(),
                  },
                ],
              };
            };

            return {
              ...thread,
              rootComment: updateReactions(thread.rootComment),
              replies: thread.replies.map(updateReactions),
            };
          });

          newThreads.set(questionId, updatedThreads);
        });

        return newThreads;
      });
    },
    [currentUser],
  );

  const removeReaction = useCallback(
    (commentId: string, emoji: string) => {
      if (!currentUser) {
        return;
      }

      setThreads((prev) => {
        const newThreads = new Map(prev);

        newThreads.forEach((questionThreads, questionId) => {
          const updatedThreads = questionThreads.map((thread) => {
            const updateReactions = (comment: Comment): Comment => {
              if (comment.id !== commentId) {
                return comment;
              }

              return {
                ...comment,
                reactions: comment.reactions.filter(
                  (r) => !(r.emoji === emoji && r.userId === currentUser.id),
                ),
              };
            };

            return {
              ...thread,
              rootComment: updateReactions(thread.rootComment),
              replies: thread.replies.map(updateReactions),
            };
          });

          newThreads.set(questionId, updatedThreads);
        });

        return newThreads;
      });
    },
    [currentUser],
  );

  const markNotificationRead = useCallback((notificationId: string) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === notificationId ? { ...n, isRead: true } : n)),
    );
  }, []);

  const markAllNotificationsRead = useCallback(() => {
    setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })));
  }, []);

  const saveDraft = useCallback(
    (questionId: string, content: string, mentions: Mention[], parentId?: string) => {
      const key = getDraftKey(questionId, parentId);
      setDrafts((prev) => {
        const newDrafts = new Map(prev);
        newDrafts.set(key, {
          questionId,
          parentId,
          content,
          mentions,
          savedAt: new Date(),
        });
        return newDrafts;
      });
    },
    [],
  );

  const getDraft = useCallback(
    (questionId: string, parentId?: string): CommentDraft | undefined => {
      const key = getDraftKey(questionId, parentId);
      return drafts.get(key);
    },
    [drafts],
  );

  const getThreadsForQuestion = useCallback(
    (questionId: string): CommentThread[] => {
      return threads.get(questionId) || [];
    },
    [threads],
  );

  const getCommentCount = useCallback(
    (questionId: string): number => {
      const questionThreads = threads.get(questionId) || [];
      return questionThreads.reduce((count, thread) => count + 1 + thread.replies.length, 0);
    },
    [threads],
  );

  const value: CommentsContextValue = {
    threads,
    notifications,
    unreadCount,
    drafts,
    currentUser,
    teamMembers,
    setCurrentUser,
    setTeamMembers,
    addComment,
    editComment,
    deleteComment,
    resolveThread,
    pinComment,
    addReaction,
    removeReaction,
    markNotificationRead,
    markAllNotificationsRead,
    saveDraft,
    getDraft,
    clearDraft,
    getThreadsForQuestion,
    getCommentCount,
  };

  return <CommentsContext.Provider value={value}>{children}</CommentsContext.Provider>;
};

