const initialState: UserPreferencesState = {
  preferences: defaultPreferences,
  interactions: [],
  usagePatterns: [],
  featureUsage: [],
  navigationPatterns: [],
  shortcutUsage: [],
  questionBehavior: new Map(),
  insights: [],
