/**
 * Hook to track component interactions
 */
export const useInteractionTracking = (componentName: string) => {
  const { trackClick, trackFeatureUsage } = useUserPreferences();

  return {
    trackClick: useCallback(
      (target: string, metadata?: Record<string, unknown>) => {
        trackClick(`${componentName}.${target}`, metadata);
      },
      [componentName, trackClick],
    ),

    trackFeature: useCallback(() => {
      trackFeatureUsage(componentName);
    }, [componentName, trackFeatureUsage]),
  };
};

/**
 * Hook to track question interactions
 */
export const useQuestionTracking = (questionId: string) => {
  const { trackQuestionBehavior } = useUserPreferences();
  const startTimeRef = useRef<number>(Date.now());

  useEffect(() => {
    trackQuestionBehavior(questionId, 'view');
    startTimeRef.current = Date.now();
  }, [questionId, trackQuestionBehavior]);

  return {
    trackAnswer: useCallback(() => {
      const duration = Date.now() - startTimeRef.current;
      trackQuestionBehavior(questionId, 'answer', duration);
    }, [questionId, trackQuestionBehavior]),

    trackSkip: useCallback(() => {
      trackQuestionBehavior(questionId, 'skip');
    }, [questionId, trackQuestionBehavior]),

    trackEdit: useCallback(() => {
      trackQuestionBehavior(questionId, 'edit');
    }, [questionId, trackQuestionBehavior]),
  };
};

/**
 * AIErrorDiagnosis.tsx - AI-Powered Error Classification & Resolution
 * Sprint 36 Task 2: ML error classification, suggest fixes, auto-apply safe fixes
 *
 * Nielsen Heuristics Addressed:
 * - #9 Help users recover: Intelligent error diagnosis
 * - #10 Help and documentation: Contextual fix suggestions
 */

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';

// ============================================================================
// Types & Interfaces
// ============================================================================

/**
 * Error category classification
 */
export type ErrorCategory =
  | 'network'
  | 'authentication'
  | 'authorization'
  | 'validation'
  | 'server'
  | 'timeout'
  | 'rate_limit'
  | 'data_corruption'
  | 'resource_not_found'
  | 'conflict'
  | 'unknown';

/**
 * Error severity level
 */
export type ErrorSeverity = 'low' | 'medium' | 'high' | 'critical';

/**
 * Fix action type
 */
export type FixActionType =
  | 'retry'
  | 'refresh_token'
  | 'clear_cache'
  | 'reload_page'
  | 'contact_support'
  | 'wait_and_retry'
  | 'login'
  | 'upgrade_plan'
  | 'check_input'
  | 'rollback'
  | 'manual';

/**
 * Classified error with diagnosis
 */
export interface ClassifiedError {
  id: string;
  originalError: Error;
  category: ErrorCategory;
  severity: ErrorSeverity;
  confidence: number;
  timestamp: Date;
  context: ErrorContext;
  suggestedFixes: SuggestedFix[];
  appliedFix?: AppliedFix;
  resolved: boolean;
}

/**
 * Error context for classification
 */
export interface ErrorContext {
  url?: string;
  method?: string;
  statusCode?: number;
  requestId?: string;
  userId?: string;
  sessionId?: string;
  page?: string;
  component?: string;
  action?: string;
  additionalData?: Record<string, unknown>;
}

/**
 * Suggested fix for an error
 */
export interface SuggestedFix {
  id: string;
  type: FixActionType;
  description: string;
  confidence: number;
  autoApplicable: boolean;
  priority: number;
  estimatedSuccess: number;
  instructions?: string[];
}

/**
 * Applied fix record
 */
export interface AppliedFix {
  fixId: string;
  type: FixActionType;
  appliedAt: Date;
  autoApplied: boolean;
  success: boolean;
  resultMessage?: string;
}

/**
 * Error pattern for learning
 */
export interface ErrorPattern {
  id: string;
  pattern: RegExp | string;
  category: ErrorCategory;
  severity: ErrorSeverity;
  suggestedFixes: Omit<SuggestedFix, 'id'>[];
  occurrences: number;
  lastSeen: Date;
  successfulFixes: Map<FixActionType, number>;
}

/**
 * AI diagnosis context value
 */
export interface AIErrorDiagnosisContextValue {
  errors: ClassifiedError[];
  patterns: ErrorPattern[];
  isLearning: boolean;
  autoFixEnabled: boolean;

  // Actions
  diagnoseError: (error: Error, context?: ErrorContext) => Promise<ClassifiedError>;
  applyFix: (errorId: string, fixId: string) => Promise<boolean>;
  recordFixResult: (errorId: string, success: boolean, message?: string) => void;
  dismissError: (errorId: string) => void;
  clearErrors: () => void;
  setAutoFixEnabled: (enabled: boolean) => void;
  getErrorStats: () => ErrorStats;
}

/**
 * Error statistics
 */
export interface ErrorStats {
  totalErrors: number;
  byCategory: Record<ErrorCategory, number>;
  bySeverity: Record<ErrorSeverity, number>;
  resolvedCount: number;
  autoFixedCount: number;
  averageResolutionTime: number;
}

