  );
};

// ============================================================================
// Breadcrumb Component
// ============================================================================

export interface BreadcrumbsProps {
  /** Override items from context */
  items?: BreadcrumbItem[];
  /** Override config from context */
  config?: Partial<BreadcrumbConfig>;
  /** Custom class name */
  className?: string;
}

export const Breadcrumbs: React.FC<BreadcrumbsProps> = ({
  items: propItems,
  config: propConfig,
  className = '',
}) => {
  const context = useContext(BreadcrumbContext);

  const items = propItems || context?.items || [];
  const config: BreadcrumbConfig = {
    ...(context?.config || {}),
    ...propConfig,
  };

  const {
    separator = '/',
    maxItems = 5,
    ariaLabel = 'Breadcrumb navigation',
    showIcons = true,
  } = config;

  // Truncate if needed
  const displayItems = useMemo(() => {
    if (items.length <= maxItems) {
      return items;
    }

    const first = items.slice(0, 1);
    const last = items.slice(-2);
    return [...first, { label: '...', title: `${items.length - 3} more items` }, ...last];
  }, [items, maxItems]);

  if (displayItems.length === 0) {
    return null;
  }

  return (
    <nav aria-label={ariaLabel} className={`breadcrumbs ${className}`}>
      <ol className="breadcrumbs__list" itemScope itemType="https://schema.org/BreadcrumbList">
        {displayItems.map((item, index) => (
          <li
            key={index}
            className={`breadcrumbs__item ${item.isCurrent ? 'breadcrumbs__item--current' : ''}`}
            itemProp="itemListElement"
            itemScope
            itemType="https://schema.org/ListItem"
          >
            {index > 0 && (
              <span className="breadcrumbs__separator" aria-hidden="true">
                {separator}
              </span>
            )}

            <BreadcrumbLink item={item} showIcon={showIcons} position={index + 1} />
          </li>
        ))}
      </ol>

      <style>{`
        .breadcrumbs {
          padding: 12px 0;
        }

        .breadcrumbs__list {
          display: flex;
          flex-wrap: wrap;
          align-items: center;
          gap: 4px;
          list-style: none;
          margin: 0;
          padding: 0;
          font-size: 14px;
        }

        .breadcrumbs__item {
          display: flex;
          align-items: center;
          gap: 4px;
        }

        .breadcrumbs__separator {
          color: #a0aec0;
          margin: 0 4px;
          user-select: none;
        }

        .breadcrumbs__link {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          color: #4a5568;
          text-decoration: none;
          padding: 4px 8px;
          border-radius: 4px;
          transition: all 0.15s;
        }

        .breadcrumbs__link:hover {
          color: #2b6cb0;
          background: #ebf8ff;
        }

        .breadcrumbs__link:focus {
          outline: 2px solid #3182ce;
          outline-offset: 2px;
        }

        .breadcrumbs__link--current {
          color: #1a202c;
          font-weight: 500;
          pointer-events: none;
        }

        .breadcrumbs__link--ellipsis {
          color: #a0aec0;
          cursor: default;
        }

        .breadcrumbs__icon {
          font-size: 14px;
          line-height: 1;
        }

        .breadcrumbs__label {
          max-width: 200px;
          overflow: hidden;
          text-overflow: ellipsis;
          white-space: nowrap;
        }

        @media (max-width: 640px) {
          .breadcrumbs__list {
            font-size: 13px;
          }

          .breadcrumbs__label {
            max-width: 100px;
          }

          .breadcrumbs__item:not(:last-child):not(:first-child) .breadcrumbs__label {
            display: none;
          }

          .breadcrumbs__item:not(:last-child):not(:first-child) .breadcrumbs__icon {
            margin: 0;
          }
        }
      `}</style>
    </nav>
  );
};

